SELECT 
FROM vso_order_version_diff t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.order_version_id = #{orderVersionId}


    AND t.field_name = #{fieldName}


    AND t.change_category = #{changeCategory}

ORDER BY t.id DESC

